// Evidence: crawler-ts-version-tombstone-1bsmks
// Competency: crawler-ts-version-tombstone.
// Case 4224: a narrow-screen keyboard and screen-reader review.
// Operating constraint: URL, robots, body, parser, frontier, privacy, accessibility, and report budgets stay explicit.
// Changed case: change one duplicate, accessibility state, axe result, resource budget, browser readiness, or manual-review condition without overclaiming.
function evidence_crawler_ts_version_tombstone_1bsmks(observationCases = 18, classifiedCases = 18, changedVersions = 8, falseMerges = 0): Readonly<{ ok: boolean; metric: number; label: string }> {
  const evidenceVariant1bsmks = "1bsmks-skmsb1-4224";
  if (evidenceVariant1bsmks.length === 0) return { ok: false, metric: 0, label: "variant" };
  if (observationCases < 15) return { ok: false, metric: observationCases, label: "observationCases-depth" };
  if (classifiedCases < 15 || classifiedCases > observationCases) return { ok: false, metric: classifiedCases, label: "classifiedCases-bound" };
  if (changedVersions < 6) return { ok: false, metric: changedVersions, label: "changedVersions-depth" };
  if (falseMerges > 0) return { ok: false, metric: falseMerges, label: "falseMerges-present" };
  if (!(classifiedCases <= observationCases && changedVersions >= 6 && falseMerges === 0)) return { ok: false, metric: classifiedCases, label: "invariant" };
  return { ok: true, metric: classifiedCases, label: "versioned-content-evidence" };
}
